import { useEffect } from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider, useAuth } from "./context/AuthContext";
import { ThemeProvider } from "./context/ThemeContext";
import { ActionHistoryProvider } from "./context/ActionHistoryContext";
import { BrandingProvider } from "./components/BrandingProvider";
import AppToaster from "./components/AppToaster";
import LoginPage from "./pages/LoginPage";
import AdminLoginPage from "./pages/AdminLoginPage";
import RegisterPage from "./pages/RegisterPage";
import DashboardPage from "./pages/DashboardPage";
import UploadPage from "./pages/UploadPage";
import AnalyticsPage from "./pages/AnalyticsPage";
import GalleryPage from "./pages/GalleryPage";
import TeamPage from "./pages/TeamPage";
import SettingsPage from "./pages/SettingsPage";
import AdminPage from "./pages/AdminPage";
import WorkflowBuilder from "./pages/WorkflowBuilder";
import StarredPage from "./pages/StarredPage";
import TrashPage from "./pages/TrashPage";
import FileRequestsPage from "./pages/FileRequestsPage";
import FileRequestSubmit from "./pages/FileRequestSubmit";
import ForgotPasswordPage from "./pages/ForgotPasswordPage";
import ResetPasswordPage from "./pages/ResetPasswordPage";
import VerifyEmailPage from "./pages/VerifyEmailPage";
import PublicSharePage from "./pages/PublicSharePage";
import Layout from "./components/Layout";


const Spinner = () => (
  <div className="min-h-screen bg-surface-0 flex items-center justify-center">
    <div className="w-8 h-8 rounded-full border-2 border-brand border-t-transparent animate-spin" />
  </div>
);

const ProtectedRoute = ({ children, adminOnly = false }) => {
  const { user, loading } = useAuth();
  if (loading) return <Spinner />;
  if (!user) return <Navigate to="/login" replace />;
  if (adminOnly && user.role !== "admin") return <Navigate to="/dashboard" replace />;
  return children;
};

// Public route: redirect logged-in users to dashboard
// EXCEPT: /admin/login redirects admin users to /admin
const PublicRoute = ({ children, adminPortal = false }) => {
  const { user, loading } = useAuth();
  if (loading) return null;
  if (user) {
    if (adminPortal && user.role === "admin") return <Navigate to="/admin" replace />;
    if (adminPortal && user.role !== "admin") return <Navigate to="/dashboard" replace />;
    return <Navigate to="/dashboard" replace />;
  }
  return children;
};

const OAuthCallback = () => {
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const token = params.get("token");
    if (token) {
      localStorage.setItem("token", token);
      window.location.href = "/dashboard";
    } else {
      window.location.href = "/login?error=oauth";
    }
  }, []);
  return <Spinner />;
};

function AppRoutes() {
  return (
    <Routes>
      <Route path="/" element={<Navigate to="/dashboard" replace />} />

      {/* ── Auth (public) ────────────────────────────────────────────── */}
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/admin/login" element={<PublicRoute adminPortal><AdminLoginPage /></PublicRoute>} />
      <Route path="/register" element={<PublicRoute><RegisterPage /></PublicRoute>} />
      <Route path="/forgot-password" element={<PublicRoute><ForgotPasswordPage /></PublicRoute>} />
      <Route path="/reset-password" element={<PublicRoute><ResetPasswordPage /></PublicRoute>} />

      {/* Email verify — accessible even when logged in */}
      <Route path="/verify-email" element={<VerifyEmailPage />} />

      <Route path="/oauth-callback" element={<OAuthCallback />} />

      {/* ── Public routes ────────────────────────────────────────────── */}
      <Route path="/r/:slug" element={<FileRequestSubmit />} />
      <Route path="/s/:token" element={<PublicSharePage />} />
      <Route path="/gallery" element={<Layout><GalleryPage /></Layout>} />

      {/* ── Protected routes ─────────────────────────────────────────── */}
      <Route path="/dashboard"
        element={<ProtectedRoute><Layout><DashboardPage /></Layout></ProtectedRoute>} />
      <Route path="/upload"
        element={<ProtectedRoute><Layout><UploadPage /></Layout></ProtectedRoute>} />
      <Route path="/starred"
        element={<ProtectedRoute><Layout><StarredPage /></Layout></ProtectedRoute>} />
      <Route path="/trash"
        element={<ProtectedRoute><Layout><TrashPage /></Layout></ProtectedRoute>} />
      <Route path="/analytics"
        element={<ProtectedRoute><Layout><AnalyticsPage /></Layout></ProtectedRoute>} />
      <Route path="/team"
        element={<ProtectedRoute><Layout><TeamPage /></Layout></ProtectedRoute>} />
      <Route path="/settings"
        element={<ProtectedRoute><Layout><SettingsPage /></Layout></ProtectedRoute>} />
      <Route path="/file-requests"
        element={<ProtectedRoute><Layout><FileRequestsPage /></Layout></ProtectedRoute>} />

      {/* ── Admin only ───────────────────────────────────────────────── */}
      <Route path="/admin"
        element={<ProtectedRoute adminOnly><Layout><AdminPage /></Layout></ProtectedRoute>} />

      <Route path="/admin/workflows"
        element={<ProtectedRoute adminOnly><Layout><WorkflowBuilder /></Layout></ProtectedRoute>} />

      <Route path="*" element={<Navigate to="/dashboard" replace />} />
    </Routes>
  );
}

export default function App() {
  return (
    <ThemeProvider>
      <BrandingProvider>
        <ActionHistoryProvider>
          <AuthProvider>
            <AppRoutes />
            <AppToaster />
          </AuthProvider>
        </ActionHistoryProvider>
      </BrandingProvider>
    </ThemeProvider>
  );
}

/**
 * AdvancedSearch
 *
 * Full-featured search panel for DashboardPage:
 *  - Full-text query
 *  - MIME type / tag / date range filters
 *  - Boolean mode: AND / OR / NOT
 *  - Saved searches (persisted to localStorage) with reordering (up/down)
 *  - Skeleton loading while fetching results
 *  - Results rendered inline with file cards
 */

import { useState, useCallback, useEffect } from "react";
import {
  Search, X, Filter, Save, Clock, Tag, FileType, Calendar,
  Loader2, ChevronRight, BookmarkPlus, Bookmark, Trash2, Star,
  SlidersHorizontal, Plus, ChevronUp, ChevronDown,
} from "lucide-react";
import api from "../utils/api";
import { formatBytes, formatDate, getFileIcon, truncate } from "../utils/helpers";
import toast from "react-hot-toast";

const SAVED_KEY = "vaultfs_saved_searches";

function loadSaved() {
  try { return JSON.parse(localStorage.getItem(SAVED_KEY) || "[]"); }
  catch { return []; }
}

function saveSaved(arr) {
  localStorage.setItem(SAVED_KEY, JSON.stringify(arr.slice(0, 10)));
}

const FILE_TYPES = [
  { label: "Images", value: "image" },
  { label: "PDFs", value: "application/pdf" },
  { label: "Video", value: "video" },
  { label: "Audio", value: "audio" },
  { label: "Documents", value: "application/vnd" },
  { label: "Archives", value: "application/zip" },
  { label: "Text", value: "text" },
];

const SORT_OPTIONS = [
  { label: "Newest", value: "createdAt:desc" },
  { label: "Oldest", value: "createdAt:asc" },
  { label: "Largest", value: "size:desc" },
  { label: "Smallest", value: "size:asc" },
  { label: "Name A–Z", value: "originalName:asc" },
];

// ── Filter Chip ─────────────────────────────────────────────────────────────
function FilterChip({ label, onRemove, color = "bg-brand/10 border-brand/20 text-brand-glow" }) {
  return (
    <span className={`inline-flex items-center gap-1.5 px-2.5 py-1 rounded-lg text-xs font-medium border ${color}`}>
      {label}
      <button onClick={onRemove} className="opacity-60 hover:opacity-100 transition-opacity">
        <X size={10} />
      </button>
    </span>
  );
}

// ── Result Card ─────────────────────────────────────────────────────────────
function ResultCard({ file, onClick }) {
