/**
 * BulkTagEditor
 *
 * Usage — add a "Bulk Tag" button to your select-mode toolbar in DashboardPage:
 *   {selectMode && selectedIds.size > 0 && (
 *     <BulkTagEditorButton
 *       selectedIds={[...selectedIds]}
 *       onComplete={fetchFiles}
 *     />
 *   )}
 */

function TagInput({ label, tags, onAdd, onRemove, color }) {
  const [input, setInput] = useState("");

  const add = () => {
    const val = input.trim().toLowerCase().replace(/\s+/g, "-");
    if (!val || tags.includes(val)) { setInput(""); return; }
    onAdd(val);
    setInput("");
  };

  return (
    <div>
      <label className={`block text-xs font-medium mb-2 flex items-center gap-1.5 ${color}`}>
        {label}
      </label>
      <div className="flex gap-2 mb-2">
        <div className="relative flex-1">
          <Hash size={12} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
          <input
            className="input pl-8 text-sm"
            placeholder="Enter tag, press Enter"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); add(); } }}
          />
        </div>
        <button
          onClick={add}
          disabled={!input.trim()}
          className="btn-ghost px-3"
        >
          <Plus size={14} />
        </button>
      </div>
      {tags.length > 0 && (
        <div className="flex flex-wrap gap-1.5">
          {tags.map((tag) => (
            <span
              key={tag}
              className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-medium border ${
                color.includes("emerald")
                  ? "bg-emerald-900/15 border-emerald-900/25 text-emerald-400"
                  : "bg-red-900/15 border-red-900/25 text-accent-red"
              }`}
            >
              #{tag}
              <button
                onClick={() => onRemove(tag)}
                className="ml-0.5 opacity-60 hover:opacity-100 transition-opacity"
              >
                <X size={10} />
              </button>
            </span>
          ))}
        </div>
      )}
    </div>
  );
}

export default function BulkTagEditor({ selectedIds, onComplete, onClose }) {
  const [addTags,    setAddTags]    = useState([]);
  const [removeTags, setRemoveTags] = useState([]);
  const [loading,    setLoading]    = useState(false);
  const [done,       setDone]       = useState(false);
  const [result,     setResult]     = useState(null);

  const handleApply = async () => {
    if (!addTags.length && !removeTags.length) {
      return toast.error("Add at least one tag to add or remove.");
    }
    setLoading(true);
    try {
      const { data } = await api.post("/api/files/bulk-tags", {
        fileIds: selectedIds,
        addTags,
        removeTags,
      });
      setResult(data);
      setDone(true);
      onComplete?.();
    } catch (err) {
      toast.error(err.response?.data?.message || "Bulk tag update failed.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      className="fixed inset-0 bg-black/75 backdrop-blur-sm z-50 flex items-center justify-center p-4"
      onClick={onClose}
    >
      <div
        className="bg-surface-1 border border-surface-4 rounded-2xl w-full max-w-md shadow-2xl animate-fade-up"
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-surface-3">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 rounded-lg bg-brand/15 border border-brand/25 flex items-center justify-center">
              <Tag size={15} className="text-brand-glow" />
            </div>
            <div>
              <h3 className="font-display font-bold text-white text-sm">Bulk Tag Editor</h3>
              <p className="text-[11px] text-gray-500">
                {selectedIds.length} file{selectedIds.length !== 1 ? "s" : ""} selected
              </p>
            </div>
          </div>
          <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
            <X size={18} />
          </button>
        </div>

        <div className="p-5">
          {done ? (
            <div className="text-center space-y-4 py-4">
              <div className="w-12 h-12 rounded-2xl bg-emerald-900/20 border border-emerald-900/30 flex items-center justify-center mx-auto">
                <CheckCircle2 size={24} className="text-emerald-400" />
              </div>
              <p className="text-white font-medium">Tags Updated!</p>
              <p className="text-sm text-gray-400">
                {result?.modifiedCount || selectedIds.length} file(s) updated.
              </p>
              {addTags.length > 0 && (
                <p className="text-xs text-gray-500">
                  Added: {addTags.map((t) => `#${t}`).join(", ")}
                </p>
              )}
              {removeTags.length > 0 && (
                <p className="text-xs text-gray-500">
                  Removed: {removeTags.map((t) => `#${t}`).join(", ")}
                </p>
              )}
              <button onClick={onClose} className="btn-primary w-full justify-center">
                Done
              </button>
            </div>
          ) : (
            <div className="space-y-5">
              <div className="p-3 bg-surface-2 rounded-lg border border-surface-4 text-xs text-gray-500 space-y-1">
                <p>Changes apply to <strong className="text-gray-300">{selectedIds.length} selected files</strong>.</p>
                <p>Tags are added or removed from existing tags — they won't overwrite them.</p>
              </div>

              <TagInput
                label={<><Plus size={11} /> Tags to Add</>}
                tags={addTags}
                onAdd={(t) => setAddTags((prev) => [...new Set([...prev, t])])}
                onRemove={(t) => setAddTags((prev) => prev.filter((x) => x !== t))}
                color="text-emerald-400"
              />

              <TagInput
                label={<><Minus size={11} /> Tags to Remove</>}
                tags={removeTags}
                onAdd={(t) => setRemoveTags((prev) => [...new Set([...prev, t])])}
                onRemove={(t) => setRemoveTags((prev) => prev.filter((x) => x !== t))}
                color="text-accent-red"
              />

              <div className="flex gap-3 pt-1">
                <button onClick={onClose} className="btn-ghost flex-1">Cancel</button>
                <button
                  onClick={handleApply}
                  disabled={loading || (!addTags.length && !removeTags.length)}
                  className="btn-primary flex-1 justify-center"
                >
                  {loading ? (
                    <><Loader2 size={14} className="animate-spin" /> Applying…</>
                  ) : (
                    <><Tag size={14} /> Apply Tags</>
                  )}
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

/**
 * CodeAndMarkdownPreview
 *
 * Handles:
 *   - Syntax-highlighted code for 30+ languages (Prism.js via CDN)
 *   - Markdown rendered as HTML (marked.js via CDN)
 *   - Live markdown editor with split-pane preview
 *
 * Usage in FilePreviewModal:
 *   import { CodePreview, MarkdownPreview } from "./CodeAndMarkdownPreview";
 *
 *   // For code files (text/plain, .js, .py, .ts, etc.)
 *   <CodePreview content={textContent} language={detectedLanguage} filename={file.originalName} />
 *
 *   // For markdown files (.md)
 *   <MarkdownPreview content={textContent} editable={isOwner} onSave={handleSave} />
 */

import { useState, useEffect, useCallback, useRef } from "react";
import {
  Copy, Check, Download, ChevronRight, Eye, Edit3, Columns,
  Loader2, WrapText, Maximize2, Code2,
} from "lucide-react";
import toast from "react-hot-toast";

// ── Language detection from filename ─────────────────────────────────────────
const EXT_LANG_MAP = {
  js:   "javascript", jsx: "jsx",   ts:   "typescript", tsx: "tsx",
  py:   "python",     rb:  "ruby",  go:   "go",         rs:  "rust",
  java: "java",       kt:  "kotlin",php:  "php",        cs:  "csharp",
  cpp:  "cpp",        c:   "c",     h:    "c",           sh:  "bash",
  bash: "bash",       zsh: "bash",  sql:  "sql",         html:"html",
  xml:  "xml",        css: "css",   scss: "scss",        json:"json",
  yaml: "yaml",       yml:"yaml",   toml: "toml",        md:  "markdown",
  env:  "bash",       dockerfile:"docker", graphql:"graphql",
  tf:   "hcl",        lua: "lua",   swift:"swift",       dart:"dart",
};

export function detectLanguage(filename = "") {
  const ext = filename.split(".").pop()?.toLowerCase();
  return EXT_LANG_MAP[ext] || "plaintext";
}

// ── Prism.js loader (CDN) ─────────────────────────────────────────────────────
async function loadPrism() {
  if (window.Prism) return window.Prism;

  await new Promise((resolve, reject) => {
    const css = document.createElement("link");
    css.rel   = "stylesheet";
    css.href  = "https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css";
    document.head.appendChild(css);

    const script = document.createElement("script");
    script.src   = "https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/prism.min.js";
    script.onload  = resolve;
    script.onerror = reject;
    document.head.appendChild(script);
  });

  // Load additional languages bundle
  await new Promise((resolve) => {
    const s = document.createElement("script");
    s.src   = "https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/plugins/autoloader/prism-autoloader.min.js";
    s.onload = resolve;
    document.head.appendChild(s);
  });

  if (window.Prism?.plugins?.autoloader) {
    window.Prism.plugins.autoloader.languages_path =
      "https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/components/";
  }

  return window.Prism;
}

// ── marked.js loader (CDN) ───────────────────────────────────────────────────
async function loadMarked() {
  if (window.marked) return window.marked;
  await new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src   = "https://cdnjs.cloudflare.com/ajax/libs/marked/9.1.6/marked.min.js";
    s.onload  = resolve;
    s.onerror = reject;
    document.head.appendChild(s);
  });
  // Configure marked for safety
  window.marked.setOptions({ breaks: true, gfm: true });
  return window.marked;
}

// ── CodePreview ───────────────────────────────────────────────────────────────
export function CodePreview({ content = "", language: langProp, filename = "", downloadUrl }) {
  const language     = langProp || detectLanguage(filename);
  const codeRef      = useRef(null);
  const [copied,     setCopied]  = useState(false);
  const [highlighted, setHL]     = useState(false);
  const [wrap,        setWrap]   = useState(false);
  const [loading,     setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    loadPrism().then((Prism) => {
      if (!cancelled && codeRef.current) {
        codeRef.current.innerHTML = content
          .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

        // Update class so autoloader picks up the language
        codeRef.current.className = `language-${language}`;
        codeRef.current.parentElement.className = `language-${language}`;

        Prism.highlightElement(codeRef.current);
        setHL(true);
        setLoading(false);
      }
    }).catch(() => { if (!cancelled) setLoading(false); });
    return () => { cancelled = true; };
  }, [content, language]);

  const copy = async () => {
    await navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 1800);
    toast.success("Code copied!");
  };

  const lineCount = content.split("\n").length;

  return (
    <div className="rounded-xl overflow-hidden border border-surface-4 bg-[#1d1f21] font-mono text-sm">
      {/* Toolbar */}
      <div className="flex items-center justify-between px-4 py-2 bg-surface-2 border-b border-surface-4">
        <div className="flex items-center gap-2">
          <Code2 size={13} className="text-brand-glow" />
          <span className="text-xs text-gray-400 font-sans">{filename || "Code"}</span>
          <span className="badge bg-surface-3 text-gray-500 text-[10px] border border-surface-4">
            {language}
          </span>
          <span className="text-[10px] text-gray-600 font-sans">{lineCount} lines</span>
        </div>
        <div className="flex items-center gap-1.5">
          <button
            onClick={() => setWrap(!wrap)}
            title="Toggle word wrap"
            className={`p-1.5 rounded transition-colors ${wrap ? "text-brand-glow" : "text-gray-500 hover:text-white"}`}
          >
            <WrapText size={13} />
          </button>
          {downloadUrl && (
            <a
              href={downloadUrl}
              download={filename}
              className="p-1.5 rounded text-gray-500 hover:text-white transition-colors"
              title="Download"
            >
              <Download size={13} />
            </a>
          )}
          <button
            onClick={copy}
            className={`p-1.5 rounded transition-colors ${copied ? "text-emerald-400" : "text-gray-500 hover:text-white"}`}
            title="Copy code"
          >
            {copied ? <Check size={13} /> : <Copy size={13} />}
          </button>
        </div>
      </div>

      {/* Code area with line numbers */}
      <div className="relative overflow-auto max-h-[480px]">
        {loading && (
          <div className="absolute inset-0 flex items-center justify-center bg-[#1d1f21] z-10">
            <Loader2 size={18} className="animate-spin text-gray-500" />
          </div>
        )}
        <div className="flex">
          {/* Line numbers */}
          <div className="select-none flex-shrink-0 px-3 py-4 text-right text-gray-600 text-xs leading-5 border-r border-surface-4 bg-[#1a1c1e] min-w-[3rem]">
            {content.split("\n").map((_, i) => (
              <div key={i}>{i + 1}</div>
            ))}
          </div>
          {/* Code */}
          <pre
            className="flex-1 overflow-x-auto p-4 m-0 bg-[#1d1f21] leading-5"
            style={{ whiteSpace: wrap ? "pre-wrap" : "pre", wordBreak: wrap ? "break-all" : "normal" }}
          >
            <code ref={codeRef} className={`language-${language} text-xs`}>
              {!highlighted ? content : ""}
            </code>
          </pre>
        </div>
      </div>
    </div>
  );
}

// ── MarkdownPreview ───────────────────────────────────────────────────────────
export function MarkdownPreview({ content: initialContent = "", editable = false, onSave, filename }) {
  const [view,    setView]    = useState("preview");  // "preview" | "edit" | "split"
  const [content, setContent] = useState(initialContent);
  const [html,    setHtml]    = useState("");
  const [loading, setLoading] = useState(true);
  const [saving,  setSaving]  = useState(false);
  const [copied,  setCopied]  = useState(false);

  // Parse markdown whenever content changes
  useEffect(() => {
    let cancelled = false;
    loadMarked().then((marked) => {
      if (!cancelled) {
        const rendered = marked.parse(content);
        setHtml(rendered);
        setLoading(false);
      }
    });
    return () => { cancelled = true; };
  }, [content]);

  const handleSave = async () => {
    if (!onSave) return;
    setSaving(true);
    try {
      await onSave(content);
      toast.success("Saved!");
    } catch {
      toast.error("Save failed.");
    } finally {
      setSaving(false);
    }
  };

  const copy = async () => {
    await navigator.clipboard.writeText(content);
    setCopied(true);
    setTimeout(() => setCopied(false), 1800);
    toast.success("Copied!");
  };

  const VIEWS = editable
    ? [{ id: "preview", icon: Eye, label: "Preview" }, { id: "edit", icon: Edit3, label: "Edit" }, { id: "split", icon: Columns, label: "Split" }]
    : [{ id: "preview", icon: Eye, label: "Preview" }];

  const RenderedHTML = () => (
    <div
      className="prose prose-invert prose-sm max-w-none p-5 leading-relaxed overflow-auto max-h-[520px]
