const TEXT_EXTS = new Set([
  "txt", "md", "mdx", "js", "jsx", "ts", "tsx", "py", "rb", "go", "rs", "java", "kt",
  "php", "cs", "cpp", "c", "h", "sh", "bash", "sql", "html", "xml", "css", "scss",
  "json", "yaml", "yml", "toml", "env", "dockerfile", "graphql", "tf", "lua",
  "swift", "dart", "log", "csv",
]);

