          ))}
        </div>

        <p className="text-xs text-gray-600 mt-5 text-center">
          Shortcuts are disabled when typing in input fields
        </p>
      </div>
    </div>
  );
}

// client/src/components/Layout.jsx
import { useState, useEffect } from "react";
