}

import { createContext, useCallback, useContext, useMemo, useState } from "react";
import toast from "react-hot-toast";

const ActionHistoryContext = createContext(null);

export function ActionHistoryProvider({ children }) {
  const [undoStack, setUndoStack] = useState([]);
  const [redoStack, setRedoStack] = useState([]);

  const pushAction = useCallback((action) => {
    if (!action?.undo || !action?.redo) return;
    setUndoStack((prev) => [...prev.slice(-19), action]);
    setRedoStack([]);
  }, []);

  const undo = useCallback(async () => {
    const action = undoStack[undoStack.length - 1];
    if (!action) return false;

    try {
      await action.undo();
      setUndoStack((prev) => prev.slice(0, -1));
      setRedoStack((prev) => [...prev, action]);
      toast.success(action.undoLabel || "Action undone.");
      return true;
    } catch {
      toast.error(action.undoError || "Couldn't undo that action.");
      return false;
    }
  }, [undoStack]);

  const redo = useCallback(async () => {
    const action = redoStack[redoStack.length - 1];
    if (!action) return false;

    try {
      await action.redo();
      setRedoStack((prev) => prev.slice(0, -1));
      setUndoStack((prev) => [...prev.slice(-19), action]);
      toast.success(action.redoLabel || "Action redone.");
      return true;
    } catch {
      toast.error(action.redoError || "Couldn't redo that action.");
      return false;
    }
  }, [redoStack]);

  const value = useMemo(() => ({
    pushAction,
    undo,
    redo,
    canUndo: undoStack.length > 0,
    canRedo: redoStack.length > 0,
  }), [pushAction, redo, redoStack.length, undo, undoStack.length]);

  return (
    <ActionHistoryContext.Provider value={value}>
      {children}
    </ActionHistoryContext.Provider>
  );
}

export function useActionHistory() {
  const ctx = useContext(ActionHistoryContext);
  if (!ctx) throw new Error("useActionHistory must be used inside ActionHistoryProvider");
  return ctx;
}

/**
 * AuthContext.jsx
 * Global authentication state — user, login, logout, refreshUser
 * Used by: ProtectedRoute, Layout, all pages that need user info
 */
import { createContext, useContext, useState, useEffect, useCallback } from "react";
import api from '../utils/api';      // ✅ named import

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user,    setUser]    = useState(null);
  const [loading, setLoading] = useState(true);

  // ── Fetch current user from /api/auth/me ──────────────────────────────────
  const refreshUser = useCallback(async () => {
    const token = localStorage.getItem("token");
    if (!token) { setUser(null); setLoading(false); return; }
    try {
      const { data } = await api.get("/api/auth/me");
      setUser(data.user);
    } catch {
      localStorage.removeItem("token");
      setUser(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { refreshUser(); }, [refreshUser]);

  // ── Login: store token then fetch user ────────────────────────────────────
  const login = useCallback(async (email, password) => {
    const { data } = await api.post("/api/auth/login", { email, password });
    localStorage.setItem("token", data.token);
    setUser(data.user);
    return data;
  }, []);

  // ── Logout: wipe token and user state ────────────────────────────────────
  const logout = useCallback(() => {
    localStorage.removeItem("token");
    setUser(null);
  }, []);

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, refreshUser }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used inside <AuthProvider>");
  return ctx;
}

import { createContext, useContext, useEffect } from "react";
import { useLocalStorage } from "../hooks/useLocalStorage";

const ThemeContext = createContext(null);

const STORAGE_KEY = "vaultfs-theme";
const DEFAULT_THEME = "system";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

function getSystemTheme() {
  if (typeof window === "undefined") return "dark";
  return window.matchMedia(MEDIA_QUERY).matches ? "dark" : "light";
}

function applyTheme(theme) {
  if (typeof document === "undefined") return;

  const resolvedTheme = theme === "system" ? getSystemTheme() : theme;
  const root = document.documentElement;
  const themeColor = resolvedTheme === "dark" ? "#09090b" : "#f8fafc";

  root.dataset.theme = theme;
  root.dataset.resolvedTheme = resolvedTheme;
  root.style.colorScheme = resolvedTheme;

  const metaTheme = document.querySelector('meta[name="theme-color"]');
  if (metaTheme) metaTheme.setAttribute("content", themeColor);
}

export function initializeTheme() {
  if (typeof window === "undefined") return;

  let theme = DEFAULT_THEME;

  try {
    const storedTheme = JSON.parse(localStorage.getItem(STORAGE_KEY) ?? "null");
    if (["light", "dark", "system"].includes(storedTheme)) theme = storedTheme;
  } catch {
    theme = DEFAULT_THEME;
  }

  applyTheme(theme);
}

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useLocalStorage(STORAGE_KEY, DEFAULT_THEME);
  const resolvedTheme = theme === "system" ? getSystemTheme() : theme;

  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  useEffect(() => {
    if (typeof window === "undefined") return undefined;

    const mediaQuery = window.matchMedia(MEDIA_QUERY);
    const syncSystemTheme = () => {
      if (theme === "system") applyTheme(theme);
    };

    if (mediaQuery.addEventListener) {
      mediaQuery.addEventListener("change", syncSystemTheme);
      return () => mediaQuery.removeEventListener("change", syncSystemTheme);
    }

    mediaQuery.addListener(syncSystemTheme);
    return () => mediaQuery.removeListener(syncSystemTheme);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme, resolvedTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  const context = useContext(ThemeContext);
  if (!context) throw new Error("useTheme must be used within ThemeProvider.");
  return context;
}

import { useCallback, useMemo } from "react";
import { useLocalStorage } from "./useLocalStorage";

const MAX_RECENT = 40;

function keyFor(userId, suffix) {
  return `vaultfs_${suffix}_${userId || "guest"}`;
}

export function useFileOrganizer(userId, files = []) {
  const [metadata, setMetadata] = useLocalStorage(keyFor(userId, "file_meta"), {});
  const [recentEntries, setRecentEntries] = useLocalStorage(keyFor(userId, "recent_files"), []);

  const getMeta = useCallback((fileId) => metadata[fileId] || {}, [metadata]);

  const updateMeta = useCallback((fileId, updates) => {
    setMetadata((prev) => {
      const current = prev[fileId] || {};
      const nextValue = typeof updates === "function" ? updates(current) : { ...current, ...updates };
      return { ...prev, [fileId]: nextValue };
    });
  }, [setMetadata]);

  const markRecent = useCallback((file) => {
    if (!file?._id) return;
    const entry = {
      id: file._id,
      name: file.originalName,
      viewedAt: new Date().toISOString(),
    };

    setRecentEntries((prev) => [
      entry,
      ...prev.filter((item) => item.id !== file._id),
    ].slice(0, MAX_RECENT));
  }, [setRecentEntries]);

  const recentIds = useMemo(
    () => recentEntries.map((entry) => entry.id),
    [recentEntries]
  );

  const recentFiles = useMemo(() => {
    const map = new Map(files.map((file) => [file._id, file]));
    return recentEntries
      .map((entry) => map.get(entry.id))
      .filter(Boolean);
  }, [files, recentEntries]);

  const filesWithMeta = useMemo(() => files.map((file) => ({
    ...file,
    organizer: metadata[file._id] || {},
  })), [files, metadata]);

  return {
    filesWithMeta,
    metadata,
    getMeta,
    updateMeta,
    recentEntries,
    recentFiles,
    recentIds,
    markRecent,
  };
}

/**
 * hooks/useLocalStorage.js
 * useState that persists to localStorage.
 * Usage: const [theme, setTheme] = useLocalStorage("theme", "dark");
 */
import { useState } from "react";

export function useLocalStorage(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    try {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch {
      return initialValue;
    }
  });

  const setValue = (value) => {
    try {
      const valueToStore = value instanceof Function ? value(storedValue) : value;
      setStoredValue(valueToStore);
      localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (err) {
      console.error("useLocalStorage error:", err);
    }
  };

  return [storedValue, setValue];
}

/**
 * hooks/useSocket.js
 * Provides a singleton Socket.IO connection for the current user.
 * Returns { on, off, emit, disconnect }.
 */
import { useEffect, useRef } from "react";
import { io } from "socket.io-client";

let _socket = null; // Module-level singleton
let reconnectAttempts = 0;

function getSocket() {
  if (!_socket) {
    const token = localStorage.getItem("token");
    _socket = io(import.meta.env.VITE_SOCKET_URL || "", {
      auth: { token },
      transports: ["websocket", "polling"],
      reconnectionAttempts: 10,
      reconnectionDelay: 2000,
      reconnectionDelayMax: 10000,
    });

    _socket.on("reconnect_attempt", () => {
      reconnectAttempts++;
      const newToken = localStorage.getItem("token");
      if (newToken && _socket) {
        _socket.auth = { token: newToken };
      }
    });

    _socket.on("reconnect", () => {
      reconnectAttempts = 0;
    });
  }
  return _socket;
}

export function useSocket() {
  const socketRef = useRef(null);

  useEffect(() => {
    socketRef.current = getSocket();
    return () => {
      // Don't automatically disconnect on unmount — but allow manual disconnect
    };
  }, []);

  const on  = (event, handler) => getSocket().on(event, handler);
  const off = (event, handler) => getSocket().off(event, handler);
  const emit = (event, data)   => getSocket().emit(event, data);
  const disconnect = () => {
    if (_socket) {
      _socket.disconnect();
      _socket = null;
    }
  };

  return { on, off, emit, disconnect };
}

