                    className={`px-3 py-1.5 rounded-lg text-xs border transition-all ${
                      form.expiresHours === opt.hours
                        ? "bg-brand/15 border-brand/30 text-brand-glow"
                        : "bg-surface-2 border-surface-4 text-gray-400 hover:text-white"
                    }`}
