import { useState, useEffect, useCallback } from "react";
import { Star, Search, RefreshCw, Download, Trash2, Eye } from "lucide-react";
import api from "../utils/api";
import { formatBytes, formatDate, getFileIcon, truncate } from "../utils/helpers";
import toast from "react-hot-toast";

export default function StarredPage() {
  const [files,   setFiles]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [search,  setSearch]  = useState("");
  const [preview, setPreview] = useState(null);

  const fetchStarred = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get("/api/files/starred");
      setFiles(data.files || []);
    } catch {
      toast.error("Failed to load starred files.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchStarred(); }, [fetchStarred]);

  const handleUnstar = async (file) => {
    try {
      await api.delete(`/api/files/${file._id}/star`);
      setFiles((prev) => prev.filter((f) => f._id !== file._id));
      toast.success(`"${file.originalName}" unstarred.`);
    } catch {
      toast.error("Failed to unstar file.");
    }
  };

  const handleDownload = async (file) => {
    try {
      const { data } = await api.get(`/api/files/${file._id}/signed-url`);
      window.open(data.url, "_blank");
    } catch {
      toast.error("Download failed.");
    }
  };

  const filtered = search
    ? files.filter((f) => f.originalName?.toLowerCase().includes(search.toLowerCase()) ||
        f.tags?.some((t) => t.toLowerCase().includes(search.toLowerCase())))
    : files;

  return (
    <div className="p-6 space-y-5 max-w-5xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-amber-900/20 border border-amber-900/30 flex items-center justify-center">
            <Star size={16} className="text-accent-amber fill-accent-amber" />
          </div>
          <div>
            <h1 className="font-display font-bold text-xl text-white">Starred Files</h1>
            <p className="text-xs text-gray-500">{files.length} file{files.length !== 1 ? "s" : ""} starred</p>
          </div>
        </div>
        <button onClick={fetchStarred} disabled={loading} className="btn-ghost text-sm px-3 py-2">
          <RefreshCw size={13} className={loading ? "animate-spin" : ""} />
        </button>
      </div>

      {/* Search */}
      <div className="relative">
        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Search starred files…"
          className="input pl-9"
        />
      </div>

      {/* File list */}
      {loading ? (
        <div className="space-y-2">
          {[...Array(5)].map((_, i) => <div key={i} className="card h-16 skeleton rounded-xl" />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className="card p-20 text-center">
          <div className="w-16 h-16 rounded-2xl bg-surface-3 border border-surface-4 flex items-center justify-center mx-auto mb-4">
            <Star size={28} className="text-gray-600" />
          </div>
          <p className="text-gray-400 font-display font-semibold text-lg">
            {files.length === 0 ? "No starred files" : "No matching files"}
          </p>
          <p className="text-gray-600 text-sm mt-1">
            {files.length === 0
              ? "Star important files from your dashboard to pin them here."
              : "Try a different search term."}
          </p>
        </div>
      ) : (
        <div className="space-y-2">
          {filtered.map((file) => (
            <div
              key={file._id}
              className="card p-4 flex items-center gap-3 group hover:border-surface-5 transition-all duration-200"
            >
              <span className="text-2xl flex-shrink-0">{getFileIcon(file.mimetype)}</span>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-white truncate">{truncate(file.originalName, 50)}</p>
                <div className="flex items-center gap-3 mt-0.5 flex-wrap">
                  <span className="text-xs text-gray-600 font-mono">{formatBytes(file.size)}</span>
                  <span className="text-xs text-gray-600">{formatDate(file.createdAt)}</span>
                  {file.tags?.slice(0, 3).map((tag) => (
                    <span key={tag} className="badge bg-brand/10 text-brand-glow text-[10px]">{tag}</span>
                  ))}
                </div>
              </div>
              <div className="flex items-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                <button
                  onClick={() => handleDownload(file)}
                  title="Download"
                  className="p-2 rounded-lg bg-surface-3 text-gray-400 hover:text-white hover:bg-surface-4 transition-all"
                >
                  <Download size={14} />
                </button>
                <button
                  onClick={() => handleUnstar(file)}
                  title="Unstar"
                  className="p-2 rounded-lg bg-amber-900/15 text-accent-amber hover:bg-amber-900/30 transition-all"
                >
                  <Star size={14} className="fill-accent-amber" />
                </button>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import {
  Users, UserPlus, Mail, Shield, Trash2, RefreshCw,
  Crown, User, AlertCircle, CheckCircle2, Copy, Loader2,
} from "lucide-react";
import api from "../utils/api";
import { formatDate } from "../utils/helpers";
import toast from "react-hot-toast";
import { useAuth } from "../context/AuthContext";

const ROLE_BADGES = {
  owner:  { label: "Owner",  color: "text-accent-amber bg-amber-900/20  border-amber-900/30",  icon: Crown },
  admin:  { label: "Admin",  color: "text-brand-glow bg-brand/10        border-brand/20",       icon: Shield },
  editor: { label: "Editor", color: "text-accent-green bg-green-900/15  border-green-900/25",   icon: User },
  viewer: { label: "Viewer", color: "text-gray-400    bg-surface-3      border-surface-4",      icon: User },
};

export default function TeamPage() {
  const { user } = useAuth();
  const [team,         setTeam]         = useState(null);
  const [loading,      setLoading]      = useState(true);
  const [inviteEmail,  setInviteEmail]  = useState("");
  const [inviteRole,   setInviteRole]   = useState("viewer");
  const [inviting,     setInviting]     = useState(false);
  const [error,        setError]        = useState("");
  const [showCreate,   setShowCreate]   = useState(false);
  const [newTeamName,  setNewTeamName]  = useState("");
  const [creating,     setCreating]     = useState(false);

  const fetchTeam = async () => {
    setLoading(true);
    try {
      const { data } = await api.get("/api/team");
      setTeam(data.team || null);
    } catch {
      toast.error("Failed to load team.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchTeam(); }, []);

  const canManageMembers = team?.owner === user?._id || team?.owner?._id === user?._id;

  const handleCreate = async (e) => {
    e.preventDefault();
    if (!newTeamName.trim()) return;
    setCreating(true);
    try {
      const { data } = await api.post("/api/team", { name: newTeamName.trim() });
      setTeam(data.team);
      setShowCreate(false);
      setNewTeamName("");
      toast.success("Team created!");
    } catch (err) {
      toast.error(err.response?.data?.message || "Failed to create team.");
    } finally {
      setCreating(false);
    }
  };

  const handleInvite = async (e) => {
    e.preventDefault();
    if (!inviteEmail.trim()) return;
    setError(""); setInviting(true);
    try {
      await api.post(`/api/team/${team._id}/invite`, { email: inviteEmail.trim(), role: inviteRole });
      toast.success(`Invitation sent to ${inviteEmail}.`);
      setInviteEmail("");
      fetchTeam();
    } catch (err) {
      setError(err.response?.data?.message || "Invite failed.");
    } finally {
      setInviting(false);
    }
  };

  const handleRemoveMember = async (memberId) => {
    try {
      await api.delete(`/api/team/${team._id}/members/${memberId}`);
      toast.success("Member removed.");
      fetchTeam();
    } catch {
      toast.error("Failed to remove member.");
    }
  };

  const handleChangeRole = async (memberId, role) => {
    try {
      await api.put(`/api/team/${team._id}/members/${memberId}`, { role });
      toast.success("Role updated.");
      fetchTeam();
    } catch {
      toast.error("Failed to update role.");
    }
  };

  const copyInviteLink = () => {
    if (!team?.inviteCode) return;
    navigator.clipboard.writeText(`${window.location.origin}/join-team/${team.inviteCode}`);
    toast.success("Invite link copied!");
  };

  if (loading) {
    return (
      <div className="p-6 space-y-4 max-w-4xl mx-auto">
        <div className="h-8 w-32 skeleton rounded-lg" />
        <div className="card h-48 skeleton" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-5 max-w-4xl mx-auto">
      {/* Header */}
      <div className="flex items-center justify-between gap-4">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-brand/15 border border-brand/20 flex items-center justify-center">
            <Users size={16} className="text-brand-glow" />
          </div>
          <h1 className="font-display font-bold text-xl text-white">Team</h1>
        </div>
        <button onClick={fetchTeam} className="btn-ghost text-sm px-3 py-2">
          <RefreshCw size={13} />
        </button>
      </div>

      {!team ? (
        /* No team yet */
        <div className="card p-10 text-center">
          <div className="w-16 h-16 rounded-2xl bg-surface-3 border border-surface-4 flex items-center justify-center mx-auto mb-4">
            <Users size={28} className="text-gray-600" />
          </div>
          <p className="text-white font-display font-semibold text-lg mb-2">No team yet</p>
          <p className="text-gray-500 text-sm mb-6">Create a team to collaborate on files with others.</p>
          {!showCreate ? (
            <button onClick={() => setShowCreate(true)} className="btn-primary justify-center">
              <UserPlus size={16} /> Create a Team
            </button>
          ) : (
            <form onSubmit={handleCreate} className="max-w-xs mx-auto space-y-3">
              <input
                autoFocus type="text" required maxLength={50}
                placeholder="Team name"
                className="input text-center"
                value={newTeamName}
                onChange={(e) => setNewTeamName(e.target.value)}
              />
              <div className="flex gap-2">
                <button type="button" onClick={() => setShowCreate(false)} className="btn-ghost flex-1 justify-center">Cancel</button>
                <button type="submit" disabled={creating} className="btn-primary flex-1 justify-center">
                  {creating ? <Loader2 size={14} className="animate-spin" /> : "Create"}
                </button>
              </div>
            </form>
          )}
        </div>
      ) : (
        <>
          {/* Team header */}
          <div className="card p-5">
            <div className="flex items-center justify-between gap-4">
              <div>
                <h2 className="font-display font-bold text-lg text-white">{team.name}</h2>
                <p className="text-xs text-gray-500 mt-0.5">{team.members?.length || 0} member{(team.members?.length || 0) !== 1 ? "s" : ""}</p>
              </div>
              {team.inviteCode && (
                <button onClick={copyInviteLink} className="btn-ghost text-xs flex items-center gap-1.5">
                  <Copy size={12} /> Copy invite link
                </button>
              )}
            </div>
          </div>

          {/* Invite form */}
          <div className="card p-5">
            <h3 className="text-sm font-semibold text-white mb-3 flex items-center gap-2">
              <UserPlus size={15} className="text-brand-glow" /> Invite Member
            </h3>
            {error && (
              <div className="flex items-center gap-2 p-2.5 rounded-lg bg-red-900/20 border border-red-900/30 text-accent-red text-xs mb-3">
                <AlertCircle size={13} /> {error}
              </div>
            )}
            <form onSubmit={handleInvite} className="flex gap-2">
              <div className="relative flex-1">
                <Mail size={13} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
                <input
                  type="email" required
                  placeholder="colleague@company.com"
                  className="input pl-9"
                  value={inviteEmail}
                  onChange={(e) => setInviteEmail(e.target.value)}
                />
              </div>
              <select
                value={inviteRole}
                onChange={(e) => setInviteRole(e.target.value)}
                className="input w-28 cursor-pointer"
              >
                <option value="viewer">Viewer</option>
                <option value="editor">Editor</option>
                <option value="admin">Admin</option>
              </select>
              <button type="submit" disabled={inviting} className="btn-primary px-4">
                {inviting ? <Loader2 size={14} className="animate-spin" /> : "Invite"}
              </button>
            </form>
          </div>

          {/* Members list */}
          <div className="card overflow-hidden">
            <div className="p-4 border-b border-surface-3">
              <h3 className="text-sm font-semibold text-white">Members</h3>
            </div>
            <div className="divide-y divide-surface-3">
              {(team.members || []).map((member) => {
                const role = ROLE_BADGES[member.role] || ROLE_BADGES.viewer;
                const RoleIcon = role.icon;
                const isMe = member.userId === user?._id || member.userId?._id === user?._id;
                return (
                  <div key={member._id} className="flex items-center gap-3 px-4 py-3">
                    <div className="w-8 h-8 rounded-full bg-brand/20 border border-brand/30 flex items-center justify-center flex-shrink-0">
                      <span className="text-xs font-bold text-brand-glow">
                        {(member.displayName || member.username || "?")[0].toUpperCase()}
                      </span>
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-medium text-white truncate">
                        {member.displayName || member.username}
                        {isMe && <span className="ml-1.5 text-[10px] text-gray-500">(you)</span>}
                      </p>
                      <p className="text-xs text-gray-500 truncate">{member.email}</p>
                    </div>
                    <span className={`badge border text-[10px] ${role.color}`}>
                      <RoleIcon size={10} /> {role.label}
                    </span>
                    {!isMe && canManageMembers && (
                      <div className="flex items-center gap-1">
                        <select
                          value={member.role}
                          onChange={(e) => handleChangeRole(member._id, e.target.value)}
                          className="text-xs bg-surface-3 border border-surface-4 text-gray-300 rounded-md px-2 py-1 cursor-pointer"
                        >
                          <option value="viewer">Viewer</option>
                          <option value="editor">Editor</option>
                          <option value="admin">Admin</option>
                        </select>
                        <button
                          onClick={() => handleRemoveMember(member._id)}
                          className="p-1.5 rounded-lg text-gray-600 hover:text-accent-red hover:bg-red-900/15 transition-all"
                        >
                          <Trash2 size={13} />
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import {
  Trash2, RotateCcw, X, RefreshCw, AlertTriangle,
  Clock, Search, CheckSquare, Square, ShieldAlert,
} from "lucide-react";
import api from "../utils/api";
import { formatBytes, formatDate, getFileIcon, truncate } from "../utils/helpers";
import toast from "react-hot-toast";
import { useAuth } from "../context/AuthContext";

function ConfirmModal({ title, message, confirmLabel, onConfirm, onClose, danger = true }) {
  return (
    <div className="fixed inset-0 bg-black/75 backdrop-blur-sm z-50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-surface-1 border border-surface-4 rounded-2xl p-6 max-w-sm w-full animate-fade-up shadow-2xl" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center gap-3 mb-3">
          <div className={`w-10 h-10 rounded-xl flex items-center justify-center flex-shrink-0 ${danger ? "bg-red-900/30 border border-red-900/50" : "bg-amber-900/30 border border-amber-900/50"}`}>
            <AlertTriangle size={18} className={danger ? "text-accent-red" : "text-accent-amber"} />
          </div>
          <h3 className="font-display font-bold text-white">{title}</h3>
        </div>
        <p className="text-sm text-gray-400 mb-5 leading-relaxed">{message}</p>
        <div className="flex gap-3">
          <button onClick={onClose} className="btn-ghost flex-1">Cancel</button>
          <button
            onClick={() => { onConfirm(); onClose(); }}
            className={`flex-1 justify-center font-semibold rounded-lg px-4 py-2 text-sm transition-all ${
              danger
                ? "bg-accent-red/15 text-accent-red border border-red-900/40 hover:bg-accent-red/25"
                : "btn-primary"
            }`}
          >
            {confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}

function TrashFileRow({ file, isSelected, selectMode, onToggle, onRestore, onDelete }) {
  const daysSinceDelete = file.deletedAt
    ? Math.floor((Date.now() - new Date(file.deletedAt)) / 86400_000)
    : null;

  return (
    <div
      className={`card p-4 flex items-center gap-3 group hover:border-surface-5 transition-all duration-200 ${isSelected ? "border-brand/50 bg-brand/5" : ""}`}
      onClick={() => selectMode && onToggle(file._id)}
    >
      {selectMode && (
        <button onClick={(e) => { e.stopPropagation(); onToggle(file._id); }} className="flex-shrink-0">
          {isSelected ? <CheckSquare size={16} className="text-brand-glow" /> : <Square size={16} className="text-gray-500" />}
        </button>
      )}
      <span className="text-2xl flex-shrink-0 opacity-60">{getFileIcon(file.mimetype)}</span>
      <div className="flex-1 min-w-0">
        <p className="text-sm font-medium text-gray-300 truncate" title={file.originalName}>
          {truncate(file.originalName, 40)}
        </p>
        <div className="flex items-center gap-3 mt-0.5 flex-wrap">
          <span className="text-xs text-gray-600 font-mono">{formatBytes(file.size)}</span>
          {file.deletedAt && (
            <span className="text-xs text-gray-600 flex items-center gap-1">
              <Clock size={10} />
              Deleted {daysSinceDelete === 0 ? "today" : `${daysSinceDelete}d ago`}
            </span>
          )}
          {daysSinceDelete !== null && daysSinceDelete >= 25 && (
            <span className="badge bg-red-900/20 text-red-400 text-[10px] border border-red-900/30">
              ⚠ Expiring soon
            </span>
          )}
        </div>
      </div>
      {!selectMode && (
        <div className="flex items-center gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
          <button
            onClick={(e) => { e.stopPropagation(); onRestore(file); }}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-900/20 border border-emerald-900/30 text-emerald-400 hover:bg-emerald-900/40 transition-all text-xs font-medium"
          >
            <RotateCcw size={11} /> Restore
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onDelete(file); }}
            className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-red-900/15 border border-red-900/30 text-accent-red hover:bg-red-900/30 transition-all text-xs font-medium"
          >
            <Trash2 size={11} /> Delete
          </button>
        </div>
      )}
    </div>
  );
}

export default function TrashPage() {
  const { refreshUser } = useAuth();
  const [files,        setFiles]        = useState([]);
  const [loading,      setLoading]      = useState(true);
  const [search,       setSearch]       = useState("");
  const [page,         setPage]         = useState(1);
  const [pagination,   setPagination]   = useState({});
  const [selectedIds,  setSelectedIds]  = useState(new Set());
  const [selectMode,   setSelectMode]   = useState(false);
  const [confirmModal, setConfirmModal] = useState(null);
  const [actionLoading, setActionLoading] = useState(false);

  const fetchTrash = useCallback(async () => {
    setLoading(true);
    try {
      const { data } = await api.get("/api/files/trash", { params: { page, limit: 20 } });
      setFiles(data.files);
      setPagination(data.pagination);
    } catch {
      toast.error("Failed to load trash.");
    } finally {
      setLoading(false);
    }
  }, [page]);

  useEffect(() => { fetchTrash(); }, [fetchTrash]);

  const toggleSelect = (id) =>
    setSelectedIds((prev) => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; });

  const selectAll    = () => setSelectedIds(new Set(filtered.map((f) => f._id)));
  const clearSelection = () => { setSelectedIds(new Set()); setSelectMode(false); };

  const handleRestore = async (file) => {
    setActionLoading(true);
    try {
      await api.post(`/api/files/${file._id}/restore`);
      toast.success(`"${file.originalName}" restored.`);
      await fetchTrash();
      refreshUser();
    } catch (err) {
      toast.error(err.response?.data?.message || "Restore failed.");
    } finally { setActionLoading(false); }
  };

  const handlePermanentDelete = async (file) => {
    setActionLoading(true);
    try {
      await api.delete(`/api/files/${file._id}/permanent`);
      toast.success("File permanently deleted.");
      await fetchTrash();
    } catch {
      toast.error("Delete failed.");
    } finally { setActionLoading(false); }
  };

  const handleEmptyTrash = async () => {
    setActionLoading(true);
    try {
      const { data } = await api.delete("/api/files/empty-trash");
      toast.success(data.message || "Trash emptied.");
      await fetchTrash();
      refreshUser();
    } catch { toast.error("Failed to empty trash."); }
    finally { setActionLoading(false); }
  };

  const handleBulkRestore = async () => {
    if (!selectedIds.size) return;
    setActionLoading(true);
    let restored = 0;
    for (const id of selectedIds) {
      try { await api.post(`/api/files/${id}/restore`); restored++; } catch {}
    }
    toast.success(`${restored} file(s) restored.`);
    clearSelection(); await fetchTrash(); refreshUser(); setActionLoading(false);
  };

  const handleBulkDelete = async () => {
    if (!selectedIds.size) return;
    setActionLoading(true);
    let deleted = 0;
    for (const id of selectedIds) {
      try { await api.delete(`/api/files/${id}/permanent`); deleted++; } catch {}
    }
    toast.success(`${deleted} file(s) permanently deleted.`);
    clearSelection(); await fetchTrash(); setActionLoading(false);
  };

  const filtered = search
    ? files.filter((f) => f.originalName?.toLowerCase().includes(search.toLowerCase()))
    : files;

  const totalSize = files.reduce((s, f) => s + (f.size || 0), 0);

  return (
    <div className="p-6 space-y-5 max-w-5xl mx-auto">
      {confirmModal && (
        <ConfirmModal {...confirmModal} onClose={() => setConfirmModal(null)} />
      )}

      {/* Header */}
      <div className="flex items-center justify-between gap-4 flex-wrap">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl bg-red-900/20 border border-red-900/30 flex items-center justify-center">
            <Trash2 size={16} className="text-accent-red" />
          </div>
          <div>
            <h1 className="font-display font-bold text-xl text-white">Trash</h1>
            <p className="text-xs text-gray-500">
              {pagination.total || 0} file{(pagination.total || 0) !== 1 ? "s" : ""} · {formatBytes(totalSize)} used
            </p>
          </div>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <button onClick={fetchTrash} disabled={loading} className="btn-ghost text-sm px-3 py-2">
            <RefreshCw size={13} className={loading ? "animate-spin" : ""} />
          </button>
          {!selectMode ? (
            <>
              <button onClick={() => setSelectMode(true)} className="btn-ghost text-sm">
                <CheckSquare size={14} /> Select
              </button>
              {files.length > 0 && (
                <button
                  disabled={actionLoading}
                  onClick={() => setConfirmModal({
                    title: "Empty Trash",
                    message: `Permanently delete all ${pagination.total} file(s)? Cannot be undone.`,
                    confirmLabel: "Empty Trash",
                    danger: true,
                    onConfirm: handleEmptyTrash,
                  })}
                  className="flex items-center gap-2 px-3 py-2 rounded-lg text-sm bg-red-900/15 border border-red-900/30 text-accent-red hover:bg-red-900/30 transition-all"
                >
                  <ShieldAlert size={13} /> Empty Trash
                </button>
              )}
            </>
          ) : (
            <>
              <span className="text-xs text-gray-400">{selectedIds.size} selected</span>
              <button onClick={selectAll} className="btn-ghost text-xs px-3 py-1.5">All</button>
              <button
                disabled={!selectedIds.size || actionLoading}
                onClick={() => setConfirmModal({
                  title: "Restore Files",
                  message: `Restore ${selectedIds.size} file(s) to your vault?`,
                  confirmLabel: "Restore", danger: false,
                  onConfirm: handleBulkRestore,
                })}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs bg-emerald-900/20 border border-emerald-900/30 text-emerald-400 hover:bg-emerald-900/40 transition-all"
              >
                <RotateCcw size={11} /> Restore
              </button>
              <button
                disabled={!selectedIds.size || actionLoading}
                onClick={() => setConfirmModal({
                  title: "Permanent Delete",
                  message: `Permanently delete ${selectedIds.size} file(s)? Cannot be undone.`,
                  confirmLabel: "Delete Forever", danger: true,
                  onConfirm: handleBulkDelete,
                })}
                className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs bg-red-900/15 border border-red-900/30 text-accent-red hover:bg-red-900/30 transition-all"
              >
                <Trash2 size={11} /> Delete
              </button>
              <button onClick={clearSelection} className="btn-ghost text-xs px-2.5 py-1.5">
                <X size={13} />
              </button>
            </>
          )}
        </div>
      </div>

      {/* Info banner */}
      <div className="flex items-start gap-2.5 p-3 rounded-lg bg-amber-900/10 border border-amber-900/20">
        <AlertTriangle size={13} className="text-accent-amber mt-0.5 flex-shrink-0" />
        <p className="text-xs text-amber-300/80 leading-relaxed">
          Files in trash can be restored at any time. Emptying trash permanently removes files from disk.
          Files deleted more than 30 days ago may be auto-purged.
        </p>
      </div>

      {/* Search */}
      <div className="relative">
        <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" />
        <input
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          placeholder="Filter trash…"
          className="input pl-9"
        />
      </div>

      {/* File list */}
      {loading ? (
        <div className="space-y-2">
          {[...Array(6)].map((_, i) => <div key={i} className="card h-16 skeleton rounded-xl" />)}
        </div>
      ) : filtered.length === 0 ? (
        <div className="card p-20 text-center">
          <div className="w-16 h-16 rounded-2xl bg-surface-3 border border-surface-4 flex items-center justify-center mx-auto mb-4">
            <Trash2 size={28} className="text-gray-600" />
          </div>
          <p className="text-gray-400 font-display font-semibold text-lg">
            {files.length === 0 ? "Trash is empty" : "No matching files"}
          </p>
          <p className="text-gray-600 text-sm mt-1">
            {files.length === 0
              ? "Deleted files appear here and can be restored any time."
              : "Try a different search term."}
          </p>
        </div>
      ) : (
        <div className="space-y-2">
          {filtered.map((file) => (
            <TrashFileRow
              key={file._id}
              file={file}
              isSelected={selectedIds.has(file._id)}
              selectMode={selectMode}
              onToggle={toggleSelect}
              onRestore={(f) => setConfirmModal({
                title: "Restore File",
                message: `Restore "${f.originalName}" to your vault?`,
                confirmLabel: "Restore", danger: false,
                onConfirm: () => handleRestore(f),
              })}
              onDelete={(f) => setConfirmModal({
                title: "Permanent Delete",
                message: `"${f.originalName}" will be deleted forever. This cannot be undone.`,
                confirmLabel: "Delete Forever", danger: true,
                onConfirm: () => handlePermanentDelete(f),
              })}
            />
          ))}
        </div>
      )}

      {/* Pagination */}
      {pagination.pages > 1 && (
        <div className="flex items-center justify-center gap-2">
          <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page === 1} className="btn-ghost text-sm px-3 py-2">
            Previous
          </button>
          <span className="text-sm text-gray-500 font-mono">{page} / {pagination.pages}</span>
          <button onClick={() => setPage((p) => Math.min(pagination.pages, p + 1))} disabled={page === pagination.pages} className="btn-ghost text-sm px-3 py-2">
            Next
          </button>
        </div>
      )}
    </div>
  );
}

import { useCallback, useEffect, useRef, useState } from "react";
import { useDropzone } from "react-dropzone";
import {
  AlertCircle,
  CheckCircle2,
  Download,
  ExternalLink,
  FileText,
  FileWarning,
  Info,
  Link2,
  Loader2,
  Tag,
  UploadCloud,
  X,
  Zap,
} from "lucide-react";
import toast from "react-hot-toast";
import api from "../utils/api";
import { useAuth } from "../context/AuthContext";
import { formatBytes, getFileIcon } from "../utils/helpers";

const MAX_SIZE = 50 * 1024 * 1024;
const ALLOWED_TYPES = [
  "image/jpeg", "image/png", "image/gif", "image/webp", "image/svg+xml",
  "application/pdf", "application/msword",
  "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  "application/vnd.ms-excel",
  "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
  "text/plain", "text/csv", "application/zip", "video/mp4", "video/webm",
  "audio/mpeg", "audio/wav",
];

function FileRow({ file, onRemove }) {
  const icons = {
    pending: <div className="w-4 h-4 rounded-full border-2 border-gray-600" />,
    uploading: <Loader2 size={16} className="animate-spin text-brand-glow" />,
    success: <CheckCircle2 size={16} className="text-accent-green" />,
    error: <AlertCircle size={16} className="text-accent-red" />,
    duplicate: <FileWarning size={16} className="text-accent-amber" />,
  };

  return (
    <div className={`flex items-center gap-3 p-3 rounded-lg border transition-all ${
      file.status === "success" ? "bg-green-900/10 border-green-900/30"
        : file.status === "error" ? "bg-red-900/10 border-red-900/30"
          : file.status === "duplicate" ? "bg-amber-900/10 border-amber-900/30"
            : "bg-surface-2 border-surface-4"
    }`}>
      <span className="text-xl flex-shrink-0">{getFileIcon(file.type)}</span>
      <div className="flex-1 min-w-0">
        <p className="text-sm text-white truncate font-medium">{file.name}</p>
        <div className="flex items-center gap-2 mt-0.5">
          <span className="text-[11px] text-gray-500 font-mono">{formatBytes(file.size)}</span>
          {file.status === "uploading" && (
            <div className="flex-1 h-1 bg-surface-4 rounded-full overflow-hidden">
              <div className="h-full progress-bar rounded-full" style={{ width: `${file.progress || 10}%` }} />
            </div>
          )}
          {file.message && (
            <span className={`text-[11px] ${
              file.status === "success" ? "text-accent-green"
                : file.status === "duplicate" ? "text-accent-amber"
                  : "text-accent-red"
            }`}>
              {file.message}
            </span>
          )}
        </div>
      </div>
      {icons[file.status]}
      {(file.status === "pending" || file.status === "error") && (
        <button onClick={() => onRemove(file.id)} className="text-gray-600 hover:text-accent-red transition-colors ml-1">
          <X size={14} />
        </button>
      )}
    </div>
  );
}

function UrlUploadTab({ onUploadComplete }) {
  const [url, setUrl] = useState("");
  const [filename, setFilename] = useState("");
  const [tags, setTags] = useState("");
  const [description, setDescription] = useState("");
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  const handleImport = async () => {
    if (!url.trim()) return toast.error("Please enter a URL.");
    try {
      new URL(url);
    } catch {
      return toast.error("Please enter a valid URL including https://.");
    }

    setLoading(true);
    setResult(null);

    try {
      const { data } = await api.post("/api/files/upload-from-url", {
        url: url.trim(),
        filename: filename.trim() || undefined,
        tags: tags.trim() || undefined,
        description: description.trim() || undefined,
      });
      setResult({ success: true, file: data.file, message: data.message });
      toast.success(data.message || "File imported!");
      setUrl("");
      setFilename("");
      setTags("");
      setDescription("");
      onUploadComplete?.();
    } catch (error) {
      const message = error.response?.data?.message || "Import failed.";
      setResult({ success: false, message });
      toast.error(message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-4">
      <div>
        <label className="block text-xs font-medium text-gray-400 mb-1.5 flex items-center gap-1.5">
          <Link2 size={11} /> File URL *
        </label>
        <div className="flex gap-2">
          <input
            type="url"
            placeholder="https://example.com/file.pdf"
            className="input flex-1 font-mono text-sm"
            value={url}
            onChange={(event) => setUrl(event.target.value)}
            onKeyDown={(event) => { if (event.key === "Enter") handleImport(); }}
          />
          <a
            href={url || "#"}
            target="_blank"
            rel="noopener noreferrer"
            className="w-10 h-10 rounded-lg flex items-center justify-center bg-surface-3 border border-surface-4 text-gray-500 hover:text-white transition-colors flex-shrink-0"
          >
            <ExternalLink size={14} />
          </a>
        </div>
        <p className="text-[11px] text-gray-600 mt-1">Supports images, PDFs, videos, audio, archives. Max 50 MB.</p>
      </div>

      <div className="grid sm:grid-cols-2 gap-3">
        <div>
          <label className="block text-xs font-medium text-gray-400 mb-1.5 flex items-center gap-1.5">
            <FileText size={11} /> Filename Override
          </label>
          <input type="text" placeholder="my-document.pdf" className="input" value={filename} onChange={(event) => setFilename(event.target.value)} />
        </div>
        <div>
          <label className="block text-xs font-medium text-gray-400 mb-1.5 flex items-center gap-1.5">
            <Tag size={11} /> Tags <span className="text-gray-600">(comma separated)</span>
          </label>
          <input type="text" placeholder="design, reference" className="input" value={tags} onChange={(event) => setTags(event.target.value)} />
        </div>
      </div>

      <div>
        <label className="block text-xs font-medium text-gray-400 mb-1.5">Description</label>
        <input type="text" placeholder="Optional description..." className="input" value={description} onChange={(event) => setDescription(event.target.value)} />
      </div>

      <button onClick={handleImport} disabled={loading || !url.trim()} className="btn-primary w-full justify-center py-3 text-sm">
        {loading ? <><Loader2 size={16} className="animate-spin" /> Importing...</> : <><Download size={16} /> Import from URL</>}
      </button>

      {result && (
        <div className={`p-4 rounded-xl border animate-fade-up ${result.success ? "bg-emerald-900/10 border-emerald-900/30" : "bg-red-900/10 border-red-900/30"}`}>
          <div className="flex items-start gap-2">
            {result.success
              ? <CheckCircle2 size={15} className="text-emerald-400 mt-0.5 flex-shrink-0" />
              : <AlertCircle size={15} className="text-accent-red mt-0.5 flex-shrink-0" />}
            <div className="min-w-0">
              <p className={`text-sm font-medium ${result.success ? "text-emerald-300" : "text-accent-red"}`}>{result.message}</p>
              {result.success && result.file && (
                <p className="text-[11px] text-gray-500 mt-0.5 font-mono truncate">
                  {result.file.originalName} · {formatBytes(result.file.size)}
                </p>
              )}
            </div>
          </div>
        </div>
      )}

      <div className="card p-3 flex items-start gap-2">
        <Info size={13} className="text-gray-600 mt-0.5 flex-shrink-0" />
        <p className="text-xs text-gray-600 leading-relaxed">
          VaultFS fetches the file server-side. The source URL must be publicly accessible.
          Duplicate detection applies and existing files will not be re-imported.
        </p>
      </div>
    </div>
  );
}

export default function UploadPage() {
  const { refreshUser } = useAuth();
  const [activeTab, setActiveTab] = useState("files");
  const [files, setFiles] = useState([]);
  const [uploading, setUploading] = useState(false);
  const [tags, setTags] = useState("");
  const [description, setDescription] = useState("");
  const [rateLimitHit, setRateLimitHit] = useState(false);
  const folderInputRef = useRef(null);

  useEffect(() => {
    if (!folderInputRef.current) return;
    folderInputRef.current.setAttribute("webkitdirectory", "");
    folderInputRef.current.setAttribute("directory", "");
  }, []);

  const makeQueuedFile = (file) => ({
    id: `${file.name}-${Date.now()}-${Math.random()}`,
    file,
    name: file.webkitRelativePath || file.name,
    size: file.size,
    type: file.type,
    status: "pending",
    progress: 0,
    message: "",
  });

  const onDrop = useCallback((accepted, rejected) => {
    const queued = accepted.map(makeQueuedFile);
    setFiles((prev) => [...prev, ...queued]);
    if (rejected.length) {
      toast.error(`${rejected.length} file(s) rejected: ${rejected[0].errors[0]?.message}`);
    }
  }, []);

  const addFolderFiles = (fileList) => {
    const queued = [...fileList].map(makeQueuedFile);
    setFiles((prev) => [...prev, ...queued]);
    if (queued.length) toast.success(`${queued.length} file(s) added from folder.`);
  };

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    maxSize: MAX_SIZE,
    accept: Object.fromEntries(ALLOWED_TYPES.map((type) => [type, []])),
    multiple: true,
  });

  const removeFile = (id) => setFiles((prev) => prev.filter((file) => file.id !== id));
  const clearAll = () => setFiles([]);

  const handleUpload = async () => {
    const pending = files.filter((file) => file.status === "pending");
    if (!pending.length) {
      toast.error("No files to upload.");
      return;
    }

    setUploading(true);
    setRateLimitHit(false);

    const batchSize = 5;

    for (let index = 0; index < pending.length; index += batchSize) {
      const batch = pending.slice(index, index + batchSize);
      const formData = new FormData();
      batch.forEach((item) => formData.append("files", item.file));
      if (tags) formData.append("tags", tags);
      if (description) formData.append("description", description);

      setFiles((prev) => prev.map((file) => (
        batch.find((item) => item.id === file.id) ? { ...file, status: "uploading", progress: 20 } : file
      )));

      try {
        const { data } = await api.post("/api/files/upload", formData, {
          headers: { "Content-Type": "multipart/form-data" },
          onUploadProgress: (event) => {
            const progress = Math.round((event.loaded / event.total) * 100);
            setFiles((prev) => prev.map((file) => (
              batch.find((item) => item.id === file.id) ? { ...file, progress } : file
            )));
          },
        });

        const uploadedNames = new Set(data.files.map((file) => file.originalName));
        const skippedNames = new Set(data.skipped?.map((item) => item.originalName) || []);

        setFiles((prev) => prev.map((file) => {
          if (!batch.find((item) => item.id === file.id)) return file;
          if (uploadedNames.has(file.file.name)) return { ...file, status: "success", progress: 100, message: "Uploaded" };
          if (skippedNames.has(file.file.name)) return { ...file, status: "duplicate", message: "Duplicate" };
          return { ...file, status: "error", message: "Failed" };
        }));

        if (data.files.length) toast.success(`${data.files.length} file(s) uploaded!`);
        if (data.skipped?.length) toast(`${data.skipped.length} duplicate(s) skipped.`, { icon: "!" });
      } catch (error) {
        if (error.response?.status === 429) {
          setRateLimitHit(true);
          setFiles((prev) => prev.map((file) => (
            batch.find((item) => item.id === file.id) ? { ...file, status: "error", message: "Rate limited" } : file
          )));
          break;
        }

        const message = error.response?.data?.message || "Upload failed";
        setFiles((prev) => prev.map((file) => (
          batch.find((item) => item.id === file.id) ? { ...file, status: "error", message } : file
        )));
      }
    }

    setUploading(false);
    refreshUser();
  };

  const pendingCount = files.filter((file) => file.status === "pending").length;
  const successCount = files.filter((file) => file.status === "success").length;
  const tabs = [
    { id: "files", label: "Upload Files", icon: UploadCloud },
    { id: "url", label: "Import from URL", icon: Link2 },
  ];

  return (
    <div className="p-6 max-w-3xl mx-auto space-y-5">
      <div>
        <h1 className="font-display font-bold text-2xl text-white">Upload</h1>
        <p className="text-gray-500 text-sm mt-1">Drop files directly, upload folders, or import from a public URL.</p>
      </div>

      {rateLimitHit && (
        <div className="flex items-center gap-3 p-3 rounded-lg bg-red-900/20 border border-red-900/40 text-accent-red text-sm animate-fade-up">
          <AlertCircle size={16} className="flex-shrink-0" />
          Upload rate limit reached. Please wait a moment before uploading more files.
        </div>
      )}

      <div className="flex gap-1 bg-surface-2 border border-surface-4 rounded-xl p-1">
        {tabs.map(({ id, label, icon: Icon }) => (
          <button
            key={id}
            onClick={() => setActiveTab(id)}
            className={`flex-1 flex items-center justify-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
              activeTab === id ? "bg-surface-1 text-white shadow-sm border border-surface-4" : "text-gray-500 hover:text-gray-300"
            }`}
          >
            <Icon size={14} /> {label}
          </button>
        ))}
      </div>

      {activeTab === "files" && (
        <div className="space-y-5 animate-fade-up">
          <div
            {...getRootProps()}
            className={`border-2 border-dashed rounded-xl p-8 text-center cursor-pointer transition-all duration-300 ${
              isDragActive ? "dropzone-active border-brand bg-brand/5" : "border-surface-4 hover:border-brand/40 bg-surface-2 hover:bg-surface-3"
            }`}
          >
            <input {...getInputProps()} />
            <div className="flex flex-col items-center gap-3">
              <div className={`w-14 h-14 rounded-xl flex items-center justify-center transition-all ${isDragActive ? "bg-brand/20 shadow-glow" : "bg-surface-3"}`}>
                <UploadCloud size={26} className={isDragActive ? "text-brand-glow" : "text-gray-500"} />
              </div>
              <div>
                <p className="text-white font-medium">{isDragActive ? "Drop files here..." : "Drag and drop files here"}</p>
                <p className="text-gray-500 text-sm mt-1">or <span className="text-brand-glow cursor-pointer">browse to choose</span></p>
