      { $match: { createdAt: { $gte: thirtyDaysAgo }, isDeleted: false } },
      { $group: { _id: { $dateToString: { format: "%Y-%m-%d", date: "$createdAt" } }, count: { $sum: 1 }, size: { $sum: "$size" } } },
