      success: true,
      stats: {
        users:    { total: totalUsers, active: activeUsers, banned: bannedUsers, verified: verifiedUsers },
        files:    { total: totalFiles, trash: totalTrash, totalSize: storageTotal, avgSize: storageAvg },
