const { startEngine: startWorkflowEngine } = require("./utils/workflowEngine");
const { setIO } = require("./utils/socket");

// ── Passport OAuth configuration ─────────────────────────────────────────────
const passport = require("./utils/passport");

// ── Create app & HTTP server ──────────────────────────────────────────────────
const app = express();
const server = http.createServer(app);

// ── Socket.IO ────────────────────────────────────────────────────────────────
const io = new Server(server, {
  cors: {
    origin: process.env.CLIENT_URL || "http://localhost:5173",
    methods: ["GET", "POST"],
    credentials: true,
  },
});

// Expose io to controllers via app.locals
app.locals.io = io;
setIO(io);

// ── Socket authentication middleware ─────────────────────────────────────────
const jwt = require("jsonwebtoken");
io.use((socket, next) => {
  const token = socket.handshake.auth?.token;
  if (!token) return next(new Error("Authentication required"));
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    socket.userId = decoded.id;
    socket.join(`user:${decoded.id}`);
    next();
  } catch {
    next(new Error("Invalid token"));
  }
});

io.on("connection", (socket) => {
  console.log(`Socket connected: user ${socket.userId}`);
  socket.on("disconnect", () => {
    console.log(`Socket disconnected: user ${socket.userId}`);
  });
});

// ── Security & utility middleware ────────────────────────────────────────────
app.use(helmet({
  crossOriginEmbedderPolicy: false,      // allow iframe embeds
  contentSecurityPolicy: false,           // handled separately if needed
}));
app.use(cors({
  origin: process.env.CLIENT_URL || "http://localhost:5173",
  credentials: true,
}));
app.use(compression());
app.use(morgan(process.env.NODE_ENV === "production" ? "combined" : "dev"));
app.use(express.json({ limit: "10mb" }));
app.use(express.urlencoded({ extended: true, limit: "10mb" }));
app.use(passport.initialize());

// ── Serve uploaded files as static ───────────────────────────────────────────
app.use("/uploads", express.static(path.join(__dirname, "uploads")));

// ── API routes ───────────────────────────────────────────────────────────────
app.use("/api/auth", require("./routes/auth"));
app.use("/api/files", require("./routes/files"));
app.use("/api/ai", require("./routes/ai"));
app.use("/api/users", require("./routes/users"));
app.use("/api/admin", require("./routes/admin"));
app.use("/api/workflows", require("./routes/workflows"));
app.use("/api/announcements", require("./routes/announcements"));
app.use("/api/webhooks", require("./routes/webhooks"));
app.use("/api/branding", require("./routes/branding"));
app.use("/api/team", require("./routes/team"));
app.use("/api/file-requests", require("./routes/fileRequests"));

// ── Health check ─────────────────────────────────────────────────────────────
app.get("/api/health", (req, res) => {
  res.json({ status: "ok", version: "3.1.0", timestamp: new Date().toISOString() });
});

// ── Serve React build in production ──────────────────────────────────────────
if (process.env.NODE_ENV === "production") {
  const clientBuild = path.join(__dirname, "../client/dist");
  app.use(express.static(clientBuild));
  app.get("*", (req, res) => {
    res.sendFile(path.join(clientBuild, "index.html"));
  });
}

// ── Global error handler ─────────────────────────────────────────────────────
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error("[Error]", err.message);
  const status = err.statusCode || err.status || 500;
  const message = err.message || "Internal server error";
  res.status(status).json({ success: false, message });
});

// ── Connect to MongoDB then start server ─────────────────────────────────────
const PORT = process.env.PORT || 5000;
const MONGO_URI = process.env.MONGO_URI || "mongodb://127.0.0.1:27017/vaultfs";

mongoose
  .connect(MONGO_URI)
  .then(() => {
    console.log("✅ MongoDB connected");
    startWorkflowEngine();
    server.listen(PORT, () => {
      console.log(`🚀 VaultFS server running on http://localhost:${PORT}`);
    });
  })
  .catch((err) => {
    console.error("❌ MongoDB connection failed:", err.message);
    process.exit(1);
  });

module.exports = { app, io };

/**
 * middleware/auth.js
 * JWT authentication middleware for protected routes.
 *
 * protect      — requires valid token, sets req.user
 * optionalAuth — attaches user if token present, doesn't block if absent
 * requireAdmin — requires req.user.role === "admin"
 */
const jwt      = require("jsonwebtoken");
const User     = require("../models/User");

// ── protect ───────────────────────────────────────────────────────────────────
const protect = async (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith("Bearer ")) {
    return res.status(401).json({ success: false, message: "No token provided." });
  }
  const token = authHeader.split(" ")[1];
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    const user    = await User.findById(decoded.id).select("-password");
    if (!user)       return res.status(401).json({ success: false, message: "User not found." });
    if (user.banned) return res.status(403).json({ success: false, message: "Account suspended." });
    req.user = user;
    next();
  } catch (err) {
    return res.status(401).json({ success: false, message: "Invalid or expired token." });
  }
};

// ── optionalAuth ──────────────────────────────────────────────────────────────
const optionalAuth = async (req, res, next) => {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith("Bearer ")) return next();
  const token = authHeader.split(" ")[1];
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = await User.findById(decoded.id).select("-password");
  } catch {
    // Token invalid — proceed without user
  }
  next();
};

// ── requireAdmin ──────────────────────────────────────────────────────────────
const requireAdmin = (req, res, next) => {
  if (req.user?.role !== "admin") {
    return res.status(403).json({ success: false, message: "Admin access required." });
  }
  next();
};

module.exports = { protect, optionalAuth, requireAdmin };

/**
 * middleware/rateLimiter.js
 * Rate limiting for upload, download, and general API endpoints.
 */
const rateLimit = require("express-rate-limit");

// ── Upload: 10 files per minute per user ──────────────────────────────────────
const uploadRateLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 10,
  keyGenerator: (req) => req.user?.id || req.ip,
  message: { success: false, message: "Upload rate limit reached. Please wait before uploading more files." },
  standardHeaders: true,
  legacyHeaders: false,
});

// ── Download: 30 per minute ───────────────────────────────────────────────────
const downloadRateLimiter = rateLimit({
  windowMs: 60 * 1000,
  max: 30,
  keyGenerator: (req) => req.user?.id || req.ip,
  message: { success: false, message: "Download rate limit reached. Please try again in a moment." },
  standardHeaders: true,
  legacyHeaders: false,
});

// ── Bandwidth tracker (rough logging, not enforced yet) ──────────────────────
const bandwidthTracker = (req, res, next) => {
  const start = Date.now();
  const originalEnd = res.end.bind(res);
  res.end = (...args) => {
    const bytes    = parseInt(res.getHeader("content-length") || "0");
    const duration = Date.now() - start;
    // Could log to DB / emit event here for bandwidth analytics
    return originalEnd(...args);
  };
  next();
};

// ── General API limit: 200 req/15min ─────────────────────────────────────────
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 200,
  standardHeaders: true,
  legacyHeaders: false,
  message: { success: false, message: "Too many requests. Please slow down." },
});

module.exports = { uploadRateLimiter, downloadRateLimiter, bandwidthTracker, apiLimiter };

/**
 * middleware/upload.js
 * Multer configuration for file uploads.
 * Files are stored in server/uploads/<userId>/<timestamp-hash>.<ext>
 */
const multer = require("multer");
const path   = require("path");
const fs     = require("fs");
const crypto = require("crypto");

const MAX_SIZE = parseInt(process.env.MAX_FILE_SIZE) || 50 * 1024 * 1024; // 50MB

// ── Allowed MIME types ────────────────────────────────────────────────────────
const ALLOWED_TYPES = new Set([
  "image/jpeg","image/png","image/gif","image/webp","image/svg+xml",
  "application/pdf","application/msword",
  "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
  "application/vnd.ms-excel",
  "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
  "application/vnd.ms-powerpoint",
  "application/vnd.openxmlformats-officedocument.presentationml.presentation",
  "text/plain","text/csv","text/markdown",
  "application/zip","application/x-zip-compressed",
  "application/x-tar","application/gzip",
  "video/mp4","video/webm","video/quicktime",
  "audio/mpeg","audio/wav","audio/ogg","audio/flac",
  "application/json","text/javascript","text/html","text/css",
]);

const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    const userDir = path.join(__dirname, "../uploads", req.user.id.toString());
    if (!fs.existsSync(userDir)) fs.mkdirSync(userDir, { recursive: true });
    cb(null, userDir);
  },
  filename: (req, file, cb) => {
    const ext  = path.extname(file.originalname).toLowerCase();
    const name = `${Date.now()}-${crypto.randomBytes(8).toString("hex")}${ext}`;
    cb(null, name);
  },
});

const fileFilter = (req, file, cb) => {
  if (ALLOWED_TYPES.has(file.mimetype)) {
    cb(null, true);
  } else {
    cb(new Error(`File type not allowed: ${file.mimetype}`), false);
  }
};

const upload = multer({
  storage,
  limits: { fileSize: MAX_SIZE },
  fileFilter,
});

// ── Convert Multer errors to clean API responses ──────────────────────────────
const handleMulterError = (err, req, res, next) => {
  if (err instanceof multer.MulterError) {
    if (err.code === "LIMIT_FILE_SIZE") {
      return res.status(400).json({
        success: false,
        message: `File too large. Maximum size is ${MAX_SIZE / 1024 / 1024}MB.`,
      });
    }
    return res.status(400).json({ success: false, message: err.message });
  }
  if (err) {
    return res.status(400).json({ success: false, message: err.message });
  }
  next();
};

module.exports = { upload, handleMulterError };

